{
  "summary": "The extraction is semantically accurate to the receipt image but fails to match the gold labels due to differences in field partitioning and date formatting. Notably, the gold label for 'tax' is incorrect (it matches the total), whereas the prediction correctly identifies the tax as 0.7. The prediction also failed to capture metadata for the line item.",
  "failure_reasons": [
    "Field partitioning mismatch (Company and Address)",
    "Date format mismatch",
    "Gold label error (Tax field)",
    "Missing line item metadata (raw_text and evidence_ids)"
  ],
  "field_notes": {
    "company": "The gold label includes the street address within the company field, which the prediction omitted.",
    "date": "The prediction uses MM/DD/YY format, while the gold label uses YYYY-MM-DD.",
    "address": "The prediction included the street address, whereas the gold label only contained the city, state, and zip.",
    "tax": "The gold label is erroneous, listing the total (10.70) as the tax. The prediction correctly extracted 0.7 from the receipt.",
    "line_items": "The prediction failed to extract the 'raw_text' and 'evidence_ids' for the line item."
  }
